css:
.vbes-testimonial {
  max-width: 640px;
  margin: 0 auto;
  padding: 48px 32px;
  text-align: center;
}
.vbes-testimonial__quote {
  font-size: 1.25rem;
  line-height: 1.7;
  color: #333;
  margin: 0 0 24px;
  font-style: italic;
  position: relative;
  padding: 0 16px;
}
.vbes-testimonial__quote::before {
  content: '\201C';
  font-size: 4rem;
  color: {{accent_color}};
  position: absolute;
  top: -20px;
  left: -8px;
  line-height: 1;
}
.vbes-testimonial__author {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.vbes-testimonial__name {
  font-weight: 700;
  font-size: 1rem;
  color: #1a1a1a;
}
.vbes-testimonial__role {
  font-size: 0.875rem;
  color: #777;
}
